('spanish:8-1-technology-in-everyday-life:tf:726bc98e', 'spanish', 'spanish:8-1-technology-in-everyday-life', '8.1 Technology in Everyday Life', 'tf', 'tf', 1, '{"question": "‘adicto/a’ agrees with gender like a normal adjective."}'::jsonb, '{"answer": true, "explain": "soy adicto (masc.) / soy adicta (fem.)."}'::jsonb),
